    # Connector-side PII handling (drop / hash named fields BEFORE they land)
    # --------------------------------------------------------------------------- #


    def parse_pii(options: dict[str, str]) -> dict | None:
        """Build PII config from options, or None if no PII handling is requested.

        ``pii_drop_fields`` / ``pii_hash_fields`` are comma-separated dotted paths
        (e.g. ``card.pan, member.ssn``). Dropped fields never land; hashed fields are
        replaced with ``sha256(salt + value)`` so they land pseudonymized.
        """
        drop = frozenset(p.strip() for p in options.get("pii_drop_fields", "").split(",") if p.strip())
        hashed = frozenset(
            p.strip() for p in options.get("pii_hash_fields", "").split(",") if p.strip()
        )
        if not drop and not hashed:
            return None
        return {"drop": drop, "hash": hashed, "salt": options.get("pii_hash_salt", "")}


    def _walk_to_parent(obj: Any, parts: list[str]):
        """Return the parent dict holding the leaf key, or None if the path is absent."""
        for p in parts[:-1]:
            if not isinstance(obj, dict) or p not in obj:
                return None
            obj = obj[p]
        return obj if isinstance(obj, dict) else None


    def apply_pii(doc: dict, pii: dict | None) -> dict:
        """Drop and/or hash configured fields on a JSON-safe document, in place."""
        if not pii:
            return doc
        for path in pii["drop"]:
            parent = _walk_to_parent(doc, path.split("."))
            if parent is not None:
                parent.pop(path.split(".")[-1], None)
        for path in pii["hash"]:
            parent = _walk_to_parent(doc, path.split("."))
            leaf = path.split(".")[-1]
            if parent is not None and parent.get(leaf) is not None:
                digest = hashlib.sha256((pii["salt"] + str(parent[leaf])).encode()).hexdigest()
                parent[leaf] = digest
        return doc


    # --------------------------------------------------------------------------- #
    # _id codec (handles ObjectId and non-ObjectId keys) + bronze row builders
    # --------------------------------------------------------------------------- #


    def encode_id(_id: Any) -> dict:
        """Encode a document ``_id`` into a JSON-safe, type-preserving offset value."""
        if isinstance(_id, ObjectId):
            return {"t": "oid", "v": str(_id)}
        return {"t": "raw", "v": convert_value(_id)}


    def decode_id(enc: dict | None) -> Any:
        """Reconstruct a queryable ``_id`` value from :func:`encode_id` output."""
        if not enc:
            return None
        return ObjectId(enc["v"]) if enc.get("t") == "oid" else enc["v"]


    def _doc_row(
        op: str,
        _id: Any,
        db: str,
        coll: str,
        document_obj: Any,
        cluster_time: int | None,
        pii: dict | None = None,
    ) -> dict:
        import json

        if document_obj is not None and pii:
            document_obj = apply_pii(document_obj, pii)
        return {
            COL_ID: str(_id),
            COL_OP: op,
            COL_CLUSTER_TIME: cluster_time,
            COL_DB: db,
            COL_COLLECTION: coll,
            COL_DOCUMENT: json.dumps(document_obj) if document_obj is not None else None,
        }


    def snapshot_row(
        doc: dict, db: str, coll: str, cluster_time: int | None = None, pii: dict | None = None
    ) -> dict:
        return _doc_row(OP_SNAPSHOT, doc.get("_id"), db, coll, convert_document(doc), cluster_time, pii)


    def append_row(
        doc: dict, db: str, coll: str, cluster_time: int | None = None, pii: dict | None = None
    ) -> dict:
        return _doc_row(OP_INSERT, doc.get("_id"), db, coll, convert_document(doc), cluster_time, pii)


    def change_row(change: dict, db: str, coll: str, pii: dict | None = None) -> dict:
        """Map an insert/update/replace/delete change-stream event to a bronze row."""
        full = change.get("fullDocument")
        if full is None:  # delete events (soft-delete mode) carry only the pre-image
            full = change.get("fullDocumentBeforeChange")
        _id = (change.get("documentKey") or {}).get("_id")
        document_obj = convert_document(full) if full is not None else None
        return _doc_row(
            change.get("operationType"),
            _id,
            db,
            coll,
            document_obj,
            bson_ts_to_long(change.get("clusterTime")),
            pii,
        )


    def delete_row(change: dict, db: str, coll: str, pii: dict | None = None) -> dict:
        """Map a delete change-stream event to a tombstone row (pre-image if available)."""
        _id = (change.get("documentKey") or {}).get("_id")
        before = change.get("fullDocumentBeforeChange")
        document_obj = convert_document(before) if before is not None else None
        return _doc_row(
            OP_DELETE, _id, db, coll, document_obj, bson_ts_to_long(change.get("clusterTime")), pii
        )


    # --------------------------------------------------------------------------- #
    # Offset model — opaque JSON-safe dicts the framework checkpoints
    # --------------------------------------------------------------------------- #


    def bson_ts_to_long(ts: Timestamp | None) -> int | None:
        """Encode a BSON cluster Timestamp as a sortable long (seconds<<32 | inc)."""
        if ts is None:
            return None
        return (int(ts.time) << 32) | int(ts.inc)


    def append_offset(last_id: str | None) -> dict:
        """Offset for append/incremental tables — cursor on the last ``_id`` seen."""
        return {"phase": "append", "last_id": last_id}


    def stream_offset(resume_token: dict | None, cluster_time: int | None) -> dict:
        """Offset for cdc tables — change-stream resume token + cluster time fallback."""
        return {"phase": "stream", "resume_token": resume_token, "cluster_time": cluster_time}


    def is_same_offset(a: dict | None, b: dict | None) -> bool:
        """Framework convergence is equality-only; normalise None/{} as equivalent."""
        return (a or {}) == (b or {})


    ########################################################
    # src/databricks/labs/community_connector/sources/mongodb/mongodb_cdc.py
    ########################################################

    CHANGE_STREAM_HISTORY_LOST = 286


    def current_cluster_time(client) -> int | None:
        """Cluster ``operationTime`` as a sortable long — pins the snapshot->tail boundary."""
        hello = client.admin.command("hello")
        return bson_ts_to_long(hello.get("operationTime"))


    def _emit_metric(db: str, coll: str, kind: str, count: int) -> None:
        """Emit a structured per-batch metric line (surfaces in pipeline task logs).

        Row-count/throughput is already in the SDP event log (flow_progress); this adds
        per-collection CDC throughput visibility for ops.
        """
        print(
            json.dumps(
                {"mongo_connector_metric": {"ns": f"{db}.{coll}", "kind": kind, "events": count}}
            )
        )


    def _open_stream(
        collection,
        resume_token,
        start_at_long,
        pipeline,
        idle_ms,
        full_document="updateLookup",
        pre_image=False,
    ):
        kwargs = {"max_await_time_ms": idle_ms}
        if full_document:
            kwargs["full_document"] = full_document
        if pre_image:
            kwargs["full_document_before_change"] = "whenAvailable"
        if resume_token:
            # startAfter is a superset of resumeAfter — it also resumes across an
            # invalidate (collection drop/rename), where resumeAfter would fail.
            kwargs["start_after"] = resume_token
        elif start_at_long:
            from bson.timestamp import Timestamp

            kwargs["start_at_operation_time"] = Timestamp(
                start_at_long >> 32, start_at_long & 0xFFFFFFFF
            )
        return collection.watch(pipeline=pipeline, **kwargs)


    def _drain(stream, row_fn, db, coll, max_records, pii=None) -> tuple[list, object]:
        """Collect up to ``max_records`` immediately-available events into bronze rows."""
        rows, token = [], None
        while len(rows) < max_records:
            change = stream.try_next()  # blocks up to max_await_time_ms, then returns None
            if change is None:
                break
            rows.append(row_fn(change, db, coll, pii))
            token = stream.resume_token
        return rows, token


    def read_change_batch(
        collection, db, coll, offset, max_records, idle_ms, pii=None, include_deletes=False
    ) -> tuple[Iterator[dict], dict]:
        """Tail insert/update/replace events; converge when idle.

        With ``include_deletes`` (soft-delete mode), delete events are emitted into the
        same stream as rows with ``_operation=delete`` (carrying the pre-image) instead
        of being physically applied — downstream filters ``_operation != 'delete'`` for
        the live view but retains the deletion as a record.

        On ``ChangeStreamHistoryLost`` (resume token aged out of the oplog), signal a
        re-snapshot by returning an ``initial``-phase offset pinned to a fresh cluster
        time — the connector then re-reads the collection and reopens the tail gaplessly.
        """
        resume_token = offset.get("resume_token")
        t0 = offset.get("t0")
        ops = ["insert", "update", "replace"]
        if include_deletes:
            ops.append("delete")
        pipeline = [{"$match": {"operationType": {"$in": ops}}}]
        try:
            with _open_stream(
                collection, resume_token, t0, pipeline, idle_ms, pre_image=include_deletes
            ) as stream:
                rows, token = _drain(stream, change_row, db, coll, max_records, pii)
        except OperationFailure as e:
            if e.code == CHANGE_STREAM_HISTORY_LOST:
                fresh = current_cluster_time(collection.database.client)
                return iter([]), {"phase": "initial", "last_id": None, "t0": fresh, "resync": True}
            raise
        end = stream_offset(token or resume_token, t0)
        if not rows:
            return iter([]), offset
        _emit_metric(db, coll, "cdc", len(rows))
        return iter(rows), end


    def read_delete_batch(
        collection, db, coll, offset, max_records, idle_ms, pii=None
    ) -> tuple[Iterator[dict], dict]:
        """Tail delete events; emit tombstones (with pre-image when enabled).

        On ``ChangeStreamHistoryLost``, restart the delete tail from a fresh cluster
        time (deletes are forward-only; the paired data re-snapshot reconciles state).
        """
        offset = offset or {}
        resume_token = offset.get("resume_token")
        t0 = offset.get("t0")
        if not resume_token and t0 is None:
            t0 = current_cluster_time(collection.database.client)
        pipeline = [{"$match": {"operationType": "delete"}}]
        try:
            with _open_stream(
                collection, resume_token, t0, pipeline, idle_ms, full_document=None, pre_image=True
            ) as stream:
                rows, token = _drain(stream, delete_row, db, coll, max_records, pii)
        except OperationFailure as e:
            if e.code == CHANGE_STREAM_HISTORY_LOST:
                fresh = current_cluster_time(collection.database.client)
                return iter([]), {"phase": "stream", "resume_token": None, "t0": fresh}
            raise
        end = stream_offset(token or resume_token, t0)
        if not rows:
            return iter([]), (offset or {"phase": "stream", "resume_token": None, "t0": t0})
        _emit_metric(db, coll, "delete", len(rows))
        return iter(rows), end


